  ('2d216435-d754-451a-aa86-e7ad8e5ef9ab'::uuid, 'ca30c0a3-e592-4210-8502-193d1198c09a'::uuid, null, 'product_updated', 'codex_blackmores_clean_approval', '{"id":"ca30c0a3-e592-4210-8502-193d1198c09a","title":"Blackmores Lutein-Vision Advanced™","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"40e4806a-5049-4668-8d29-ab36a31202dd","category":null,"currency":"THB","platform":"manual","title_en":"Blackmores Lutein-Vision Advanced™","title_th":null,"image_url":"https://images.contentstack.io/v3/assets/blt948bd74310fc0ad0/blte117f7e0ccf04adf/68bfb9b474e06c57fcb62737/9300807338131-1.webp","brand_name":"blackmores","created_at":"2026-05-21T13:09:46.565855+00:00","source_url":"https://www.blackmores.com.au/products/lutein-vision-advanced","updated_at":"2026-05-21T13:09:46.578212+00:00","admin_notes":null,"description":"Blackmores Lutein-Vision Advanced™ supports vision and macular health with antioxidants and omega-3s.","product_url":"https://www.blackmores.com.au/products/lutein-vision-advanced","label_status":"parsed","price_amount":null,"product_kind":"supplement","description_en":"Blackmores Lutein-Vision Advanced™ supports vision and macular health with antioxidants and omega-3s.","description_th":null,"normalized_url":"https://www.blackmores.com.au/products/lutein-vision-advanced","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"dosage":"for use. Read the","locale":"en","parser":"blackmores_structured_ingredients_v2","titleEn":"Blackmores Lutein-Vision Advanced™","htmlLength":162995,"validation":{"status":"pass","reasons":[],"summary":"2 matchable canonical facts.","checkedAt":"2026-05-21T13:09:46.575Z","matchableFactCount":2},"description":"Blackmores Lutein-Vision Advanced™ supports vision and macular health with antioxidants and omega-3s.","descriptionEn":"Blackmores Lutein-Vision Advanced™ supports vision and macular health with antioxidants and omega-3s.","descriptionTh":null,"extractedText":"Blackmores Lutein-Vision Advanced Capsules All Products Shop All Products New Products Best Sellers Vegan Certified Women&#x27;s Health Men&#x27;s Health Kid&#x27;s Health Infant & Toddler Nutrition By Category Arthritis, Joint & Bone Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutritional Oils Heart Health Infant & Toddler Nutrition Kids&#x27; Health Men&#x27;s Health Multivitamins Muscle Support Nails, Hair & Skin Preconception, Pregnancy & Breastfeeding Stress Relief & Sleep Support Women&#x27;s Health By Ingredient Calcium CoQ10 Curcumin Echinacea Fish Oil & Omega 3 Glucosamine Iron Magnesium Probiotics Selenium Vitamin B Vitamin C Vitamin D Vitamin E Zinc Health Hub By Categories By Type Latest Articles Action Plans Arthritis, Bone & Joint Beauty & Skincare Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutrition Oils Heart & Cardiovascular Health Kids & Infant Health Men&#x27;s Health Muscle Support & Fitness Preconception, Pregnancy & Breastfeeding Recipes Stress Relief & Sleep Support Women&#x27;s Health Action Plans Articles Recipes Latest Articles About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Pillars Our People & Culture Our Careers Our Ambassadors & Partners Contact us Ask A Naturopath Our Newsroom Blackmores Subscribe Search Home Chevron Icon Horizontal products Chevron Icon Horizontal Blackmores Lutein-Vision Advanced™ Size Size 60 capsules Good health changes everything—support your eye health daily with Blackmores Lutein-Vision Advanced™. This advanced formulation provides lutein and zeaxanthin to support healthy eye function, especially of the macula and retina. The inclusion of omega-3 fatty acids and selenium helps deliver antioxidant benefits and contributes to reducing free radical damage to body cells. This product is designed to maintain healthy eyesight and general eye structure function. Taken daily, it supports long-term vision health and general wellbeing, especially for those concerned with eye nutrition. Product Format Capsule Always read the label and follow the directions for use. Read the warnings before purchase. Support For Macula Health Eye Health No Added Yeast No Added Gluten No Added Wheat No Added Dairy Benefits & How To Use Benefits Provides a combination of omega 3 fish oil plus antioxidants lutein, zeaxanthin and selenium. Maintains healthy vision. Helps maintain eye retina and macula health. Antioxidant to help decrease free radical damage to the body cells. Dosage Adults Take 2 capsules once a day, or as prescribed by a health professional. Take with food. Warnings Always read the label and follow the directions for use. This product contains selenium which is toxic in high doses. A daily dose of 150 micrograms for adults of selenium from dietary supplements should not be exceeded. If you have any pre-existing conditions or are on any medications, always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains fish, soya bean products and sulfites. Benefits Dosage Warnings Provides a combination of omega 3 fish oil plus antioxidants lutein, zeaxanthin and selenium. Maintains healthy vision. Helps maintain eye retina and macula health. Antioxidant to help decrease free radical damage to the body cells. Adults Take 2 capsules once a day, or as prescribed by a health professional. Take with food. Always read the label and follow the directions for use. This product contains selenium which is toxic in high doses. A daily dose of 150 micrograms for adults of selenium from dietary supplements should not be exceeded. If you have any pre-existing conditions or are on any medications, always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains fish, soya bean products and sulfites. The Blackmores Difference Ingredients Active ingredients per capsule: Tagetes erecta (marigold) extract soft conc. 66.5 mg equivalent dry flower 499 mg standardised to lutein esters calculated as lutein 5 mg Selenomethionine 124 micrograms equivalent selenium 50 micrograms Zeaxanthin 1 mg Concentrated fish omega-3 triglycerides 850 mg equivalent eicosapentaenoic acid (EPA) 352 mg equivalent docosahexaenoic acid (DHA) 176 mg Lutein-Vision Advanced™ Reviews Let&#x27;s stay in touch Instagram Facebook TikTok LinkedIn Back To Top About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam Terms & Policies Privacy Policy & Practices Terms Of Purchase Terms of Service Posting Guidelines Social Media House Rules Terms & Policies Privacy Policy & Practices Terms Of Purchase Terms of Service Posting Guidelines Social Media House Rules Contacts & FAQs Report a Suspected Adverse Experience Contact Us Ask a Naturopath Product & Purchasing FAQs Blackmores Subscribe Contacts & FAQs Report a Suspected Adverse Experience Contact Us Ask a Naturopath Product & Purchasing FAQs Blackmores