  ('2d5703f0-9785-450e-a1ea-46145f86f3e5'::uuid, 'eac7d1b3-8be1-4ee5-add7-8d6799e6be3c'::uuid, null, 'product_updated', 'codex_blackmores_clean_approval', '{"id":"eac7d1b3-8be1-4ee5-add7-8d6799e6be3c","title":"Blackmores Omega Mini Double Concentrate","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"40e4806a-5049-4668-8d29-ab36a31202dd","category":null,"currency":"THB","platform":"manual","title_en":"Blackmores Omega Mini Double Concentrate","title_th":null,"image_url":"https://images.contentstack.io/v3/assets/blt948bd74310fc0ad0/blt9fd97b787e001bf7/68bfbb9477db243d3ea5fe0a/9300807353998-1.webp","brand_name":"blackmores","created_at":"2026-05-21T13:09:47.587817+00:00","source_url":"https://www.blackmores.com.au/products/omega-mini-double-concentrate","updated_at":"2026-05-21T13:09:47.599654+00:00","admin_notes":null,"description":"Blackmores Omega Mini Double Concentrate, a concentrated odourless fish oil in mini-sized capsules to support heart, brain, eyes, and skin health.","product_url":"https://www.blackmores.com.au/products/omega-mini-double-concentrate","label_status":"parsed","price_amount":null,"product_kind":"supplement","description_en":"Blackmores Omega Mini Double Concentrate, a concentrated odourless fish oil in mini-sized capsules to support heart, brain, eyes, and skin health.","description_th":null,"normalized_url":"https://www.blackmores.com.au/products/omega-mini-double-concentrate","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"dosage":"for use. Read the","locale":"en","parser":"blackmores_structured_ingredients_v2","titleEn":"Blackmores Omega Mini Double Concentrate","htmlLength":170243,"validation":{"status":"pass","reasons":[],"summary":"1 matchable canonical fact.","checkedAt":"2026-05-21T13:09:47.597Z","matchableFactCount":1},"description":"Blackmores Omega Mini Double Concentrate, a concentrated odourless fish oil in mini-sized capsules to support heart, brain, eyes, and skin health.","descriptionEn":"Blackmores Omega Mini Double Concentrate, a concentrated odourless fish oil in mini-sized capsules to support heart, brain, eyes, and skin health.","descriptionTh":null,"extractedText":"Blackmores Omega Mini Double Concentrate All Products Shop All Products New Products Best Sellers Vegan Certified Women&#x27;s Health Men&#x27;s Health Kid&#x27;s Health Infant & Toddler Nutrition By Category Arthritis, Joint & Bone Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutritional Oils Heart Health Infant & Toddler Nutrition Kids&#x27; Health Men&#x27;s Health Multivitamins Muscle Support Nails, Hair & Skin Preconception, Pregnancy & Breastfeeding Stress Relief & Sleep Support Women&#x27;s Health By Ingredient Calcium CoQ10 Curcumin Echinacea Fish Oil & Omega 3 Glucosamine Iron Magnesium Probiotics Selenium Vitamin B Vitamin C Vitamin D Vitamin E Zinc Health Hub By Categories By Type Latest Articles Action Plans Arthritis, Bone & Joint Beauty & Skincare Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutrition Oils Heart & Cardiovascular Health Kids & Infant Health Men&#x27;s Health Muscle Support & Fitness Preconception, Pregnancy & Breastfeeding Recipes Stress Relief & Sleep Support Women&#x27;s Health Action Plans Articles Recipes Latest Articles About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Pillars Our People & Culture Our Careers Our Ambassadors & Partners Contact us Ask A Naturopath Our Newsroom Blackmores Subscribe Search Home Chevron Icon Horizontal products Chevron Icon Horizontal Blackmores Omega Mini Double Concentrate Size Size 200 capsules 400 capsules For those who don’t eat fish regularly, Blackmores Omega Mini Double Concentrate delivers concentrated omega‑3s in a compact capsule that helps support your cardiovascular system, cognitive function, support the health of your heart, skin, eyes and brain when dietary intake is inadequate, while also helping maintain general health and wellbeing. This odourless fish oil is extracted from 100% wild-caught fish and is tested for quality and purity. Support your omega-3 intake every day - because good health changes everything. Product Format Capsule Always read the label and follow the directions for use. Read the warnings before purchase. Support For Heart and Cardiovascular Health Brain Health Eye Health Skin Health No Added Gluten No Added Wheat No Added Dairy Benefits & How To Use Benefits Support the health of your heart, eyes and brain. Supports skin health when dietary intake is inadequate. Supports nervous system health. Ideal if you don’t eat fish 2-3 times per week. Easy to swallow, odourless, mini-size capsule. Rigorously tested for mercury, dioxins and PCBs. Supports general health and wellbeing. Dosage Take only ONE dose recommendation, or as prescribed by a health professional. Take with food. Adults and children 2-17 years For general health and wellbeing : Take 1 capsule once a day. Children unable to swallow: Pierce the capsule, squeeze the content into milk, juice or cereal and consume immediately. Do not swallow whole. For cardiovascular and nervous system health : Take 1 capsule once a day. For brain, eye and skin health : Take 5 capsules once a day. Not recommended for children under 2 years. Warnings Always read the label and follow the directions before use. Use in children only under adult supervision. Not recommended for children under 2 years. KEEP OUT OF REACH OF CHILDREN. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains fish products, soya bean products and sulfites. Benefits Dosage Warnings Support the health of your heart, eyes and brain. Supports sk