  ('3b9374db-00d8-4c54-8206-25e448844101'::uuid, '817281a1-641f-405c-b397-1adab5e482f5'::uuid, null, 'product_updated', 'manufacturer_scraper_auto_review', '{"id":"817281a1-641f-405c-b397-1adab5e482f5","title":"DHC Platinum Nanocolloid 30-Day Supply 2-Pack","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"17f6ebfb-bc28-4471-84e6-12fccfd93e06","category":null,"currency":"THB","platform":"manual","title_en":"DHC Platinum Nanocolloid 30-Day Supply 2-Pack","title_th":"DHC แพลตตินัม นาโนคอลลอยด์ 30 วัน 2 ชิ้น","image_url":"https://www.dhc.co.jp/dw/image/v2/BLLL_PRD/on/demandware.static/-/Sites-dhc_catalog-ms/default/dw41daf104/large/2379/36999_G.png?sw=256&sh=256&sm=cut","brand_name":"dhc","created_at":"2026-05-21T10:14:06.987466+00:00","source_url":"https://www.dhc.co.jp/goods/36999.html","updated_at":"2026-05-21T10:14:06.999402+00:00","admin_notes":null,"description":"プラチナはサビない！ 体の中へも、プラチナパワー","product_url":"https://www.dhc.co.jp/goods/36999.html","label_status":"missing","price_amount":null,"product_kind":"supplement","description_en":"Platinum nanocolloid supplement providing 5 mcg platinum per capsule.","description_th":"อาหารเสริมแพลตตินัม นาโนคอลลอยด์ ให้แพลตตินัม 5 ไมโครกรัมต่อแคปซูล","normalized_url":"https://www.dhc.co.jp/goods/36999.html","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"locale":"ja","parser":"dhc_demandware_health_supplements_v1","titleEn":"DHC Platinum Nanocolloid 30-Day Supply 2-Pack","titleTh":"DHC แพลตตินัม นาโนคอลลอยด์ 30 วัน 2 ชิ้น","htmlHash":"c33ed0980c515c5d247c0af54476b7a7074b891c38b8c1023e0deb6d334cafdd","nutrition":"「サビない」貴金属として知られ、食品への配合が厚生労働省から認められている白金（はっきん）=プラチナ。これを2ナノサイズ（10億分の2メートル）まで超微粒子化した白金ナノコロイドを、1日摂取目安量あたり5μgも配合しました。 イキイキと若々しく毎日をすごしたい方、いつもキレイでいたい方の健康・美容ケアにおすすめです。 「ナノコロイド」とは？ 「ナノ」とは、大きさや長さの単位で「10億分の1メートル」のこと。「コロイド」とは、水の中に物質が溶けるのではなく、細かい物質が分散し溶けているように見える状態のことをさします。仮に地球を1ナノに縮小すると、ピンポン玉ほどのサイズになります。 金属を身体に入れても大丈夫？ 白金は「食品の酸化を防ぐ食品添加物」として、厚生労働省から安全性を認められている数少ない金属のひとつです。口にいれても問題なく、安心してお摂りいただけます。 安全とはいえ、やはり体内に蓄積するのでは？ と不安です ナノ化したプラチナを均一に分散させた白金ナノコロイドは、胃液で消化されず、腸でも吸収されません。 したがって白金ナノコロイドの電気的作用だけが伝導され、物質としてのプラチナが、体内に取り込まれたり蓄積される心配はありません。 JANコード： 4511413607572 ※水またはぬるま湯でお召し上がりください。 【名称】白金含有食品 【原材料名】デキストリン（国内製造）/ゼラチン、セルロース、グリセリン脂肪酸エステル、着色料（カラメル、酸化チタン）、微粒二酸化ケイ素、白金 【内容量】6.8g［1粒重量229mg（1粒内容量180mg）×30粒］ 【栄養成分表示［1粒229mgあたり］】熱量0.9kcal、たんぱく質0.05g、脂質0.004g、炭水化物0.16g、食塩相当量0.0002g、白金5μg アレルギー物質 ゼラチン 健康食品について ※一日摂取目安量を守って、お召し上がりください。 ※お身体に異常を感じた場合は、摂取を中止してください。 ※特定原材料及びそれに準ずるアレルギー物質を対象範囲として表示しています。原材料をご確認の上、食物アレルギーのある方はお召し上がりにならないでください。 ※薬を服用中あるいは通院中の方、妊娠中の方は、お医者様にご相談の上お召し上がりください。 ●直射日光、高温多湿な場所をさけて保存してください。 ●お子様の手の届かないところで保管してください。 ●開封後はしっかり開封口を閉め、なるべく早くお召し上がりください。 食生活は、主食、主菜、副菜を基本に、食事のバランスを。 レビュー 2025年以前のレビュー 肺気腫緩和に期待 2020年08月22日 池田民夫 ｜ 愛用歴：4年4ヶ月 ｜ 愛知県 ｜ 61歳 今でも、マルチビタミン・マルチミネラル・Ⅱ型コラーゲンプロテオグリカン・ルテイン・届くビフィズスEX・国産パーフェクト野菜を飲んでます。今回医者から、肺気腫と言われ、色々ネットで調べた結果、活性酸素除去が良さそうだとなり、今回注文しました、すごく期待しています。すぐに息切れするし、息苦しくもなる為、めちゃくちゃ期待です。 関連する商品 キャンペーン 送料無料 【父の日限定】アスタキサンチン 30日分 3個セット 4,617 円 3,915 円（税込） 15%off 6月21日まで カートに入れる キャンペーン ネコポス コンビニ受取 亜鉛 30日分 3個セット 810 円 783 円（税込） 3%off 6月2日まで カートに入れる キャンペーン 送料無料 ネコポス コンビニ受取 醗酵黒セサミン プレミアム 30日分 2個セット 5,940 円 5,697 円（税込） 4%off 6月25日まで カートに入れる キャンペーン 送料無料 【父の日限定】香酢（こうず） 30日分 4個セット 4,752 円 3,888 円（税込） 18%off 6月21日まで カートに入れる 関連カテゴリ 健康食品・サプリメント 健康食品・サプリメント 目的で探す 元気・スタミナ 健康食品・サプリメント 健康食品・サプリメント 目的で探す 美容 カートに追加しました この商品はすでにお気に入りリストに追加されています。 新作アイテム今すぐチェック --> 新作アイテム 今すぐチェック 新作アイテム今すぐチェック --> お買い得商品を お見逃しなく！ 新作アイテム今すぐチェック --> 最大25％OFF 業界最大級の割引率 新作アイテム今すぐチェック --> オンラインショップ 限定品 新作アイテム今すぐチェック --> 安全性を第一に考えた 製品づくり 新作アイテム今すぐチェック --> 読み物や特集ページは コチラ お得な購入特典 すべて見る 最大10%OFF！ 一括購入割引 税込3,78","productId":"36999","validation":{"status":"failed","reasons":["no_canonical_match","no_dosed_facts"],"summary":"No usable per-serving product facts.","checkedAt":"2026-05-21T10:14:06.996Z","matchableFactCount":0},"description":"プラチナはサビない！ 体の中へも、プラチナパワー","importScope":"dhc_japan_supplements","priceAmount":1550,"descriptionEn":"Platinum nanocolloid 