  ('4184fa67-6fbb-447a-9682-bb77493a746a'::uuid, '6bc9de11-8a22-4b09-a273-88ff1f9b2b6a'::uuid, null, 'product_updated', 'codex_blackmores_clean_approval', '{"id":"6bc9de11-8a22-4b09-a273-88ff1f9b2b6a","title":"Blackmores Immune Rapi-Melt™","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"40e4806a-5049-4668-8d29-ab36a31202dd","category":null,"currency":"THB","platform":"manual","title_en":"Blackmores Immune Rapi-Melt™","title_th":null,"image_url":"https://images.contentstack.io/v3/assets/blt948bd74310fc0ad0/blt875f1ea43ee79368/68c369da74e06c431ab6cadb/9300807364062-1.webp","brand_name":"blackmores","created_at":"2026-05-21T13:09:46.052881+00:00","source_url":"https://www.blackmores.com.au/products/immune-rapi-melt","updated_at":"2026-05-21T13:09:46.064451+00:00","admin_notes":null,"description":"Blackmores Immune Rapi-Melts are great tasting and support immune system health.","product_url":"https://www.blackmores.com.au/products/immune-rapi-melt","label_status":"parsed","price_amount":null,"product_kind":"supplement","description_en":"Blackmores Immune Rapi-Melts are great tasting and support immune system health.","description_th":null,"normalized_url":"https://www.blackmores.com.au/products/immune-rapi-melt","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"dosage":"for use. Read the","locale":"en","parser":"blackmores_structured_ingredients_v2","titleEn":"Blackmores Immune Rapi-Melt™","htmlLength":165639,"validation":{"status":"pass","reasons":[],"summary":"3 matchable canonical facts.","checkedAt":"2026-05-21T13:09:46.062Z","matchableFactCount":3},"description":"Blackmores Immune Rapi-Melts are great tasting and support immune system health.","descriptionEn":"Blackmores Immune Rapi-Melts are great tasting and support immune system health.","descriptionTh":null,"extractedText":"Blackmores Immune Rapi-Melt All Products Shop All Products New Products Best Sellers Vegan Certified Women&#x27;s Health Men&#x27;s Health Kid&#x27;s Health Infant & Toddler Nutrition By Category Arthritis, Joint & Bone Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutritional Oils Heart Health Infant & Toddler Nutrition Kids&#x27; Health Men&#x27;s Health Multivitamins Muscle Support Nails, Hair & Skin Preconception, Pregnancy & Breastfeeding Stress Relief & Sleep Support Women&#x27;s Health By Ingredient Calcium CoQ10 Curcumin Echinacea Fish Oil & Omega 3 Glucosamine Iron Magnesium Probiotics Selenium Vitamin B Vitamin C Vitamin D Vitamin E Zinc Health Hub By Categories By Type Latest Articles Action Plans Arthritis, Bone & Joint Beauty & Skincare Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutrition Oils Heart & Cardiovascular Health Kids & Infant Health Men&#x27;s Health Muscle Support & Fitness Preconception, Pregnancy & Breastfeeding Recipes Stress Relief & Sleep Support Women&#x27;s Health Action Plans Articles Recipes Latest Articles About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Pillars Our People & Culture Our Careers Our Ambassadors & Partners Contact us Ask A Naturopath Our Newsroom Blackmores Subscribe Search Home Chevron Icon Horizontal products Chevron Icon Horizontal Blackmores Immune Rapi-Melt™ Size Size 60 tablets 90 tablets Good health changes everything - support your immune defences with Blackmores Immune Rapi-Melt™. This convenient formula helps stimulate a healthy immune system response and support immune system health with a triple blend of nutrients: vitamin C, zinc and selenium. It offers antioxidant protection by helping reduce free radicals formed in the body and supports the body’s natural ability to fight illness. Taken daily, it also helps relieve tiredness and fatigue when dietary intake is inadequate and contributes to general wellbeing. In an easy-to-take, dissolving tablet format, Immune Rapi-Melt™ is ideal for those on the go, or who dislike swallowing tablets seeking an easy way to support their immune health. Product Format Orally disintegrating tablet (melt) Always read the label and follow the directions for use. Read the warnings before purchase. Support For Immune System Health No Added Dairy No Added Soya Bean Benefits & How To Use Benefits Great tasting. Fast dissolving. Supports immune system function. Supports immune system to fight illness. Helps stimulate a healthy immune system response. Antioxidant to reduce free radicals formed in the body. Supports energy levels. Relieves fatigue when dietary intake is inadequate. Supports general health and wellbeing. Dosage Adults Dissolve 1 melt (orally disintegrating tablet) in your mouth, two times a day. No water required. Warnings Always read the label and follow the directions for use. This medicine contains selenium which is toxic in high doses. A daily dose of 150 micrograms for adults of selenium from dietary supplements should not be exceeded. If symptoms persist, talk to your health professional. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains sulfites. Benefits Dosage Warnings Great tasting. Fast dissolving. Supports immune system function. Supports immune system to fight illness. Helps stimulate a healthy immune system response. Antioxidant to reduce free radicals formed in the body. Supports energy levels. Relieves fatigue when dietary intake is inadequate. Supports general health and wellbeing. Adults Dissolve 1 melt (orally disintegrating tablet) in your mouth, two times a day. No water required. Always read the label and follow the directions for use. This medicine contains selenium which is toxic in high doses. A daily dose of 150 micrograms for adults of selenium from dietary supplements should not be exceeded. If symptoms persist, talk to your health professional. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains sulfites. The Blackmores Difference Ingredients Active ingredients per melt: Ascorbic acid (vitamin C) 50 mg Zinc oxide 6.2 mg equivalent zinc 5 mg Selenomethionine 74 micrograms equivalent selenium 30 micrograms Immune Rapi-Melt™ Reviews Let&#x27;s stay in touch Instagram Facebook TikTok LinkedIn Back To Top About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam Terms & Policies Privacy Policy & Practices Terms Of Purchase Terms of Service Posting Guidelines Social Media House Rules Terms & Policies Privacy Policy & Practices Terms Of Purchase Terms of Service Posting Guidelines Social Media House Rules Contacts & FAQs Report a Suspected Adverse Experience Contact Us Ask a Naturopath Product & Purchasing FAQs Blackmores Subscribe Contacts & FAQs Report a Suspected Adverse Experience Contact Us Ask a Naturopath Product & Purchasing FAQs Blackmores Subscribe Back To Top Terms of Purchase Privacy Policy ©2025 Blackmores. All Rights Reserved. ©2025 Blackmores. All Rights Reserved.","productImportId":"9778bcbf-a928-4f5b-aa95-722dfe4cb3b6","aiFactCorrection":{"notes":"Standardized to canonical nutrient names/IDs from structured per-melt rows; dropped source compounds (zinc oxide, selenomethionine) in favor of elemental equivalents.","responseId":"df058603-0387-93ec-9c9b-e7ed1779c027","correctedAt":"2026-05-18T16:49:00.708Z","originalFactCount":5,"correctedFactCount":3},"activeIngredientCount":5,"structuredIngredients":[{"uid":"cs7b367c147dd5c3fc","type":"Title","units":null,"amount":null,"ingredientName":"Active ingredients per melt:"},{"uid":"cs11f47558c5e26c72","type":"Main","units":"mg","amount":50,"ingredientName":"Ascorbic acid (vitamin C)"},{"uid":"cse139d916814e0970","type":"Main","units":"mg","amount":6.2,"ingredientName":"Zinc oxide"},{"uid":"cs45946d9381512387","type":"Supporting","units":"mg","amount":5,"ingredientName":"equivalent zinc"},{"uid":"cs09ace679d8d64ca2","type":"Main","units":"micrograms","amount":74,"ingredientName":"Selenomethionine"},{"uid":"cs4d68faa3c1acff73","type":"Supporting","units":"micrograms","amount":30,"ingredientName":"equivalent selenium"}],"candidateSupplierReason":"Blackmores Thailand product pages expose structured active ingredient tables, product images and FDA advertising approval text."},"affiliate_status":"none","normalized_title":"blackmores_immune_rapi_melt","product_audience":"both","validation_status":"pass","validation_reasons":[],"validation_summary":"3 matchable canonical facts.","availability_status":"unknown","external_product_id":null,"fda_approval_number":null,"affiliate_checked_at":null,"normalized_brand_name":"blackmores","validation_checked_at":"2026-05-21T13:09:46.062+00:00","availability_cached_at":null,"product_data_expires_at":null}'::jsonb, '{"status":"approved","version":2,"changeNote":"approve_clean_blackmores_validation_